Kaj izpiše naslednji program? 
Pascal: 
var n:integer; 
function ugani(var x:integer) : integer; 
var i:integer; 
begin 
  for i:=1 to 3 do inc(x); 
  ugani:=x; 
end; 
begin 
  n:=50; 
  while (n<=60) do begin 
    write (ugani(n):3); 
  end; 
end. 
C: 
#include <stdio.h> 
int n; 
int ugani (int *x) 
{ 
  for (int i=1; i<4; i++) 
    (*x)++; 
  return *x; 
} 
void main() 
{ 
  n=50; 
  while (n<=60) { 
     printf("%3d",ugani(&n)); 
  } 
} 
A 
