Kaj izpiše dani program? 
Pascal: 
Var s : string [10]; 
    i : integer; 
    c : char; 
Begin 
  S:='matura'; 
  For i:=1 to length(s) div 2 do begin 
     c:=s [i]; 
     s [i]:=s [length(s)+1-i]; 
     s [length(s)+1-i]:=c; 
     writeln(s); 
  End; 
End. 
C: 
#include <string.h> 
#include <stdio.h> 
void main() 
{ 
     char s [10]="matura"; 
     int i; 
     char c; 
     for (i=0;i<strlen(s)/2;i++) { 
         c=s [i]; 
         s [i]=s [strlen(s)-i-1]; 
         s [strlen(s)-i-1]=c; 
         printf("%s\n",s); 
     } 
} 
